    public void handleLiquidation(Client client, Object message)
    {
        //
        // future
        //    {
        //        "e":"forceOrder",
        //        "E":1698871323061,
        //        "o":{
        //           "s":"BTCUSDT",
        //           "S":"BUY",
        //           "o":"LIMIT",
        //           "f":"IOC",
        //           "q":"1.437",
        //           "p":"35100.81",
        //           "ap":"34959.70",
        //           "X":"FILLED",
        //           "l":"1.437",
        //           "z":"1.437",
        //           "T":1698871323059
        //        }
        //    }
        // delivery
        //    {
        //        "e":"forceOrder",              // Event Type
        //        "E": 1591154240950,            // Event Time
        //        "o":{
        //            "s":"BTCUSD_200925",       // Symbol
        //            "ps": "BTCUSD",            // Pair
        //            "S":"SELL",                // Side
        //            "o":"LIMIT",               // Order Type
        //            "f":"IOC",                 // Time in Force
        //            "q":"1",                   // Original Quantity
        //            "p":"9425.5",              // Price
        //            "ap":"9496.5",             // Average Price
        //            "X":"FILLED",              // Order Status
        //            "l":"1",                   // Order Last Filled Quantity
        //            "z":"1",                   // Order Filled Accumulated Quantity
        //            "T": 1591154240949,        // Order Trade Time
        //        }
        //    }
        //
        Object rawLiquidation = this.safeValue(message, "o", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(rawLiquidation, "s");
        Object market = this.safeMarket(marketId, null, "", "contract");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object liquidation = this.parseWsLiquidation(rawLiquidation, market);
        if (Helpers.isTrue(Helpers.isEqual(this.liquidations, null)))
        {
            Object limit = this.safeInteger(this.options, "liquidationsLimit", 1000);
            this.liquidations = new ArrayCache(((Number)limit).intValue());
        }
        Object cache = this.liquidations;
        Helpers.callDynamically(cache, "append", new Object[]{liquidation});
        client.resolve(new java.util.ArrayList<Object>(java.util.Arrays.asList(liquidation)), "liquidations");
        client.resolve(new java.util.ArrayList<Object>(java.util.Arrays.asList(liquidation)), Helpers.add("liquidations::", symbol));
    }

