    /**
     * @method
     * @name binance#watchBidsAsks
     * @description watches best bid & ask for symbols
     * @see https://developers.binance.com/docs/binance-spot-api-docs/websocket-api/market-data-requests#symbol-order-book-ticker
     * @see https://developers.binance.com/docs/derivatives/coin-margined-futures/websocket-market-streams/All-Book-Tickers-Stream
     * @see https://developers.binance.com/docs/derivatives/usds-margined-futures/websocket-market-streams/All-Book-Tickers-Stream
     * @param {string[]} symbols unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchBidsAsks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            symbols = this.marketSymbols(symbols, null, true, false, true);
            Object result = (this.watchMultiTickerHelper("watchBidsAsks", "bookTicker", symbols, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return result;
            }
            return this.filterByArray(this.bidsasks, "symbol", symbols);
        });

    }

    public java.util.concurrent.CompletableFuture<Object> watchMultiTickerHelper(Object methodName, Object channelName2, Object... optionalArgs)
    {
        final Object channelName3 = channelName2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object channelName = channelName3;
            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object isUnsubscribe = Helpers.getArg(optionalArgs, 2, false);
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            symbols = this.marketSymbols(symbols, null, true, false, true);
            Object isBidAsk = (Helpers.isEqual(channelName, "bookTicker"));
            Object isMarkPrice = (Helpers.isEqual(channelName, "markPrice"));
            Object use1sFreq = this.safeBool(parameters, "use1sFreq", true);
            Object firstMarket = null;
            Object marketType = null;
            Object symbolsDefined = (!Helpers.isEqual(symbols, null));
            if (Helpers.isTrue(symbolsDefined))
            {
                firstMarket = this.market(Helpers.GetValue(symbols, 0));
            }
            Object defaultMarket = ((Helpers.isTrue((isMarkPrice)))) ? "swap" : null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams(methodName, firstMarket, parameters, defaultMarket);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams(methodName, firstMarket, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object rawMarketType = null;
            if (Helpers.isTrue(this.isLinear(marketType, subType)))
            {
                rawMarketType = "future";
            } else if (Helpers.isTrue(this.isInverse(marketType, subType)))
            {
                rawMarketType = "delivery";
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                rawMarketType = marketType;
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() does not support options markets")) ;
            }
            if (Helpers.isTrue(Helpers.isTrue(isMarkPrice) && !Helpers.isTrue(this.inArray(marketType, new java.util.ArrayList<Object>(java.util.Arrays.asList("swap", "future"))))))
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() does not support "), marketType), " markets yet")) ;
            }
            Object subscriptionArgs = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object unsubscribeMessageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object suffix = "";
            if (Helpers.isTrue(isMarkPrice))
            {
                suffix = ((Helpers.isTrue((use1sFreq)))) ? "@1s" : "";
            }
            Object unifiedPrefix = null;
            if (Helpers.isTrue(isBidAsk))
            {
                unifiedPrefix = "bidask";
            } else if (Helpers.isTrue(isMarkPrice))
            {
                unifiedPrefix = "markPrice";
            } else
            {
                unifiedPrefix = "ticker";
            }
            if (Helpers.isTrue(symbolsDefined))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
                {
                    Object symbol = Helpers.GetValue(symbols, i);
                    Object market = this.market(symbol);
                    ((java.util.List<Object>)subscriptionArgs).add(Helpers.add(Helpers.add(Helpers.add(Helpers.GetValue(market, "lowercaseId"), "@"), channelName), suffix));
                    ((java.util.List<Object>)messageHashes).add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(unifiedPrefix, ":"), channelName), "@"), symbol));
                    if (Helpers.isTrue(isUnsubscribe))
                    {
                        ((java.util.List<Object>)unsubscribeMessageHashes).add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add("unsubscribe::", unifiedPrefix), ":"), channelName), "@"), symbol));
                    }
                }
            } else
            {
                if (Helpers.isTrue(isBidAsk))
                {
                    if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
                    {
                        throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " "), methodName), "() requires symbols for this channel for spot markets")) ;
                    }
                    ((java.util.List<Object>)subscriptionArgs).add(Helpers.add("!", channelName));
                } else if (Helpers.isTrue(isMarkPrice))
                {
                    ((java.util.List<Object>)subscriptionArgs).add(Helpers.add(Helpers.add(Helpers.add("!", channelName), "@arr"), suffix));
                } else
                {
                    ((java.util.List<Object>)subscriptionArgs).add(Helpers.add(Helpers.add("!", channelName), "@arr"));
                }
                ((java.util.List<Object>)messageHashes).add(Helpers.add(Helpers.add(unifiedPrefix, "s:"), channelName));
                ((java.util.List<Object>)unsubscribeMessageHashes).add(Helpers.add("unsubscribe::", channelName));
            }
            Object streamHash = channelName;
            if (Helpers.isTrue(symbolsDefined))
            {
                streamHash = Helpers.add(Helpers.add(channelName, "::"), String.join((String)",", (java.util.List<String>)symbols));
            }
            Object url = Helpers.add(Helpers.add(this.getWsUrl(rawMarketType, this.getFutureWsCategory(channelName)), "/"), this.stream(rawMarketType, streamHash));
            Object requestId = this.requestId(url);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "method", ((Helpers.isTrue(isUnsubscribe))) ? "UNSUBSCRIBE" : "SUBSCRIBE" );
                put( "params", subscriptionArgs );
                put( "id", requestId );
            }};
            Object hashes = messageHashes;
            Object subscription = new java.util.HashMap<String, Object>() {{
                put( "id", requestId );
            }};
            if (Helpers.isTrue(isUnsubscribe))
            {
                final Object finalSymbols = symbols;
                subscription = new java.util.HashMap<String, Object>() {{
                    put( "unsubscribe", true );
                    put( "id", String.valueOf(requestId) );
                    put( "subMessageHashes", messageHashes );
                    put( "messageHashes", unsubscribeMessageHashes );
                    put( "symbols", finalSymbols );
                    put( "topic", "ticker" );
                }};
                hashes = unsubscribeMessageHashes;
            }
            Object result = (this.watchMultiple(url, hashes, this.deepExtend(request, parameters), hashes, subscription)).join();
            if (Helpers.isTrue(isUnsubscribe))
            {
                return result;
            }
            // for efficiency, we have two type of returned structure here - if symbols array was provided, then individual
            // ticker dict comes in, otherwise all-tickers dict comes in
            if (!Helpers.isTrue(symbolsDefined))
            {
                return result;
            } else
            {
                Object newDict = new java.util.HashMap<String, Object>() {{}};
                Helpers.addElementToObject(newDict, Helpers.GetValue(result, "symbol"), result);
                return newDict;
            }
        });

    }

    public Object parseWsTicker(Object message, Object marketType)
    {
        // markPrice
        //   {
        //       "e": "markPriceUpdate",   // Event type
        //       "E": 1562305380000,       // Event time
        //       "s": "BTCUSDT",           // Symbol
        //       "p": "11794.15000000",    // Mark price
        //       "i": "11784.62659091",    // Index price
        //       "P": "11784.25641265",    // Estimated Settle Price, only useful in the last hour before the settlement starts
        //       "r": "0.00038167",        // Funding rate
        //       "T": 1562306400000        // Next funding time
        //   }
        //
        // ticker
        //     {
        //         "e": "24hrTicker",      // event type
        //         "E": 1579485598569,     // event time
        //         "s": "ETHBTC",          // symbol
        //         "p": "-0.00004000",     // price change
        //         "P": "-0.209",          // price change percent
        //         "w": "0.01920495",      // weighted average price
        //         "x": "0.01916500",      // the price of the first trade before the 24hr rolling window
        //         "c": "0.01912500",      // last (closing) price
        //         "Q": "0.10400000",      // last quantity
        //         "b": "0.01912200",      // best bid
        //         "B": "4.10400000",      // best bid quantity
        //         "a": "0.01912500",      // best ask
        //         "A": "0.00100000",      // best ask quantity
        //         "o": "0.01916500",      // open price
        //         "h": "0.01956500",      // high price
        //         "l": "0.01887700",      // low price
        //         "v": "173518.11900000", // base volume
        //         "q": "3332.40703994",   // quote volume
        //         "O": 1579399197842,     // open time
        //         "C": 1579485597842,     // close time
        //         "F": 158251292,         // first trade id
        //         "L": 158414513,         // last trade id
        //         "n": 163222,            // total number of trades
        //     }
        //
        // miniTicker
        //     {
        //         "e": "24hrMiniTicker",
        //         "E": 1671617114585,
        //         "s": "MOBBUSD",
        //         "c": "0.95900000",
        //         "o": "0.91200000",
        //         "h": "1.04000000",
        //         "l": "0.89400000",
        //         "v": "2109995.32000000",
        //         "q": "2019254.05788000"
        //     }
        // fetchTickerWs
        //     {
        //         "symbol":"BTCUSDT",
        //         "price":"72606.70",
        //         "time":1712526204284
        //     }
        // fetchTickerWs - ticker.book
        //     {
        //         "lastUpdateId":1027024,
        //         "symbol":"BTCUSDT",
        //         "bidPrice":"4.00000000",
        //         "bidQty":"431.00000000",
        //         "askPrice":"4.00000200",
        //         "askQty":"9.00000000",
        //         "time":1589437530011,
        //      }
        //
        Object marketId = this.safeString2(message, "s", "symbol");
        Object symbol = this.safeSymbol(marketId, null, null, marketType);
        Object eventVar = this.safeString(message, "e", "bookTicker");
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "24hrTicker")))
        {
            eventVar = "ticker";
        }
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "markPriceUpdate")))
        {
            // handle this separately because some fields clash with the ticker fields
            return this.safeTicker(new java.util.HashMap<String, Object>() {{
                put( "symbol", symbol );
                put( "timestamp", BinanceCore.this.safeInteger(message, "E") );
                put( "datetime", BinanceCore.this.iso8601(BinanceCore.this.safeInteger(message, "E")) );
                put( "info", message );
                put( "markPrice", BinanceCore.this.safeString(message, "p") );
                put( "indexPrice", BinanceCore.this.safeString(message, "i") );
            }});
        }
        Object timestamp = null;
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "bookTicker")))
        {
            // take the event timestamp, if available, for spot tickers it is not
            timestamp = this.safeInteger2(message, "E", "time");
        } else
        {
            // take the timestamp of the closing price for candlestick streams
            timestamp = this.safeIntegerN(message, new java.util.ArrayList<Object>(java.util.Arrays.asList("C", "E", "time")));
        }
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object last = this.safeString2(message, "c", "price");
        final Object finalTimestamp = timestamp;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTimestamp );
            put( "datetime", BinanceCore.this.iso8601(finalTimestamp) );
            put( "high", BinanceCore.this.safeString(message, "h") );
            put( "low", BinanceCore.this.safeString(message, "l") );
            put( "bid", BinanceCore.this.safeString2(message, "b", "bidPrice") );
            put( "bidVolume", BinanceCore.this.safeString2(message, "B", "bidQty") );
            put( "ask", BinanceCore.this.safeString2(message, "a", "askPrice") );
            put( "askVolume", BinanceCore.this.safeString2(message, "A", "askQty") );
            put( "vwap", BinanceCore.this.safeString(message, "w") );
            put( "open", BinanceCore.this.safeString(message, "o") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", BinanceCore.this.safeString(message, "x") );
            put( "change", BinanceCore.this.safeString(message, "p") );
            put( "percentage", BinanceCore.this.safeString(message, "P") );
            put( "average", null );
            put( "baseVolume", BinanceCore.this.safeString(message, "v") );
            put( "quoteVolume", BinanceCore.this.safeString(message, "q") );
            put( "info", message );
        }}, market);
    }

    public void handleTickerWs(Client client, Object message)
    {
        //
        // ticker.price
        //    {
        //        "id":"1",
        //        "status":200,
        //        "result":{
        //            "symbol":"BTCUSDT",
        //            "price":"73178.60",
        //            "time":1712527052374
        //        }
        //    }
        // ticker.book
        //    {
        //        "id":"9d32157c-a556-4d27-9866-66760a174b57",
        //        "status":200,
        //        "result":{
        //            "lastUpdateId":1027024,
        //            "symbol":"BTCUSDT",
        //            "bidPrice":"4.00000000",
        //            "bidQty":"431.00000000",
        //            "askPrice":"4.00000200",
        //            "askQty":"9.00000000",
        //            "time":1589437530011   // Transaction time
        //        }
        //    }
        //
        Object messageHash = this.safeString(message, "id");
        Object result = this.safeValue(message, "result", new java.util.HashMap<String, Object>() {{}});
        Object ticker = this.parseWsTicker(result, "future");
        client.resolve(ticker, messageHash);
    }

